package com.trademaster.ims.mobile.checkout.dto;import jakarta.validation.constraints.*;import java.math.BigDecimal;import java.time.Instant;import java.util.List;
public final class CheckoutDtos{private CheckoutDtos(){}public record AddressRequest(@NotBlank @Size(max=40)String label,@NotBlank @Size(max=120)String recipientName,@NotBlank @Pattern(regexp="^(?:\\+?880|0)?1[3-9]\\d{8}$")String phone,@NotBlank @Size(max=250)String addressLine1,@Size(max=250)String addressLine2,@Size(max=100)String area,@NotBlank @Size(max=100)String city,@NotBlank @Size(max=100)String district,@NotBlank @Size(max=100)String division,@Size(max=20)String postalCode,@NotBlank @Size(max=80)String country,@Size(max=500)String deliveryInstructions,boolean defaultAddress){}public record AddressResponse(Long id,String label,String recipientName,String phone,String addressLine1,String addressLine2,String area,String city,String district,String division,String postalCode,String country,String deliveryInstructions,boolean defaultAddress,boolean active){}
 public record DeliveryMethodResponse(Long id,String code,String name,String description,BigDecimal deliveryCharge,int estimatedMinDays,int estimatedMaxDays,boolean eligible,String ineligibilityReason){}
 public record ReviewRequest(@NotNull Long addressId,@NotNull Long deliveryMethodId,@Size(max=50)String couponCode,@Size(max=100)String clientReviewId){}public record ReviewItem(Long cartItemId,Long productId,Long variationId,String productName,String variationName,String imageUrl,BigDecimal unitPrice,int quantity,BigDecimal lineSubtotal,BigDecimal taxRate,BigDecimal taxAmount,String stockLabel,boolean valid){}public record ReviewResponse(String reviewId,Instant reviewExpiresAt,String cartVersion,List<ReviewItem>items,BigDecimal subtotal,BigDecimal taxTotal,BigDecimal deliveryCharge,BigDecimal discountTotal,BigDecimal grandTotal,String currency,AddressResponse address,DeliveryMethodResponse deliveryMethod,List<String>blockingIssues,List<String>warnings,boolean readyToSubmit){}
 public record SubmitRequest(@NotBlank String reviewId,@NotBlank @Size(max=100)String idempotencyKey,@AssertTrue(message="Terms must be accepted")boolean termsAccepted,@Size(max=500)String customerNote){}public record OrderConfirmation(String orderNumber,Instant submittedAt,String orderStatus,String paymentStatus,BigDecimal grandTotal,String deliveryAddress,String deliveryMethod,String nextStep){}
}
